args.sparql:
SELECT ?album ?albumLabel WHERE { 
  wd:Q2282030 wdt:P1650 ?album .
  ?album rdfs:label ?albumLabel .
  FILTER(lang(?albumLabel) = 'en')
}

SELECT DISTINCT ?album ?albumLabel WHERE { 
  wd:Q2282030 wdt:P1650 ?album .
  ?album rdfs:label ?albumLabel .
  FILTER(LANG(?albumLabel) = 'en')
} LIMIT 1

SELECT ?album ?albumLabel WHERE {
  ?album wdt:P175 wd:Q6060 ;  # performer is 50 Cent
       wdt:P31 wd:Q482994 ;     # instance of album
       wdt:P577 ?date ;
       rdfs:label ?albumLabel .
  FILTER(YEAR(?date) = 2003)
  FILTER(LANG(?albumLabel) = 'en')
}
